/**
 * User notification preferences model.
 *
 * Controls how and when a user receives email notifications.
 * Currently email is the only channel; the model is designed
 * so additional channels can be added later without breaking changes.
 */

import type { NotificationType } from './notification.js';

/**
 * How often batched/digest emails are sent.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency for non-urgent notifications. */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to. */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  /** The user ID these preferences belong to. */
  id: string;
  /** User ID (same as id — preferences are keyed by user). */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** When the preferences were created. */
  createdAt: Date;
  /** When the preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'account-updated',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Create a default UserPreferences for a given user.
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  const now = new Date();
  return {
    id: userId,
    userId,
    email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES] },
    createdAt: now,
    updatedAt: now,
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const email = JSON.parse(record['email'] as string) as {
      enabled: boolean;
      frequency: string;
      subscribedCategories: string[];
    };
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: email.enabled,
        frequency: email.frequency as EmailPreferences['frequency'],
        subscribedCategories: email.subscribedCategories as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    return this.findById(userId);
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for notification preferences and a
 * shouldNotify() check that the NotificationService uses before
 * dispatching a notification.
 *
 * Default behaviour: if a user has no stored preferences, they
 * receive all notifications (opt-out model).
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { createDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none exist.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return createDefaultPreferences(userId);
  }

  /**
   * Get preferences only if they have been explicitly saved.
   * Returns undefined when the user has never customised preferences.
   */
  getSavedPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Update email preferences for a user.
   * Creates defaults first if the user has no stored preferences.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    let prefs = this.repository.findByUserId(userId);

    if (!prefs) {
      // First customisation — persist defaults, then apply changes.
      prefs = createDefaultPreferences(userId);
      this.repository.save(prefs);
      this.logger.info(`Created default preferences for user ${userId}`);
    }

    const updatedEmail = {
      ...prefs.email,
      ...input,
    };

    const updated = this.repository.update(userId, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated email preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   *
   * Returns true when:
   * 1. The user has no stored preferences (defaults = all enabled), OR
   * 2. Email is enabled AND the notification type is in their subscribed categories.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No stored preferences — default is to send everything.
    if (!prefs) {
      return true;
    }

    if (!prefs.email.enabled) {
      this.logger.info(
        `Email disabled for user ${userId}, suppressing ${notificationType}`,
      );
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} unsubscribed from ${notificationType}, suppressing`,
      );
      return false;
    }

    return true;
  }

  /**
   * Reset a user's preferences to defaults (deletes stored record).
   */
  resetPreferences(userId: string): void {
    this.repository.delete(userId);
    this.logger.info(`Reset preferences for user ${userId}`);
  }
}

